mapper.select:
SELECT c.comment_id, c.card_id, c.app_user_id, c.user_nickname, c.content, c.rating, c.comment_type, c.status, c.admin_reply, c.feedback_id, c.create_time, c.update_time, card.front_content AS card_front_content, sub.subject_name, CASE c.comment_type WHEN 'QUALITY' THEN '优质内容' WHEN 'POOR' THEN '劣质内容' ELSE '中性评价' END AS comment_type_text, CASE c.status WHEN '0' THEN '正常' WHEN '1' THEN '已处理' WHEN '2' THEN '已隐藏' ELSE '未知' END AS status_text FROM biz_card_comment c LEFT JOIN biz_card card ON c.card_id = card.card_id LEFT JOIN biz_subject sub ON card.subject_id = sub.subject_id WHERE 1=1
AND c.card_id = #{cardId}
AND c.comment_type = #{commentType}
AND c.status = #{status}
ORDER BY c.create_time DESC
